                            </div>
                          </div>
                        ))}
                        {historyList.length === 0 && <p className="text-center text-slate-400 py-10">Nenhum histórico encontrado.</p>}
                      </div>
                    )}

                    {activeTab === 'documents' && (
                       <div className="space-y-6">
