      </div>
    </>
  );
}

import React, { useState, useEffect } from 'react';
import { api } from '../supabaseClient';
import { Patient, Appointment, Anamnesis, MedicalDocument } from '../types';
import { Search, Plus, User, FileText, Calendar, Trash2, Loader, LayoutGrid, List, ScrollText, Clock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useDialog } from '../components/Dialog';

interface PatientMeta {
  hasHistory: boolean;
  hasDocs: boolean;
  hasFutureApt: boolean;
}

export default function PatientsPage() {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [meta, setMeta] = useState<Record<string, PatientMeta>>({});
  const [loadingData, setLoadingData] = useState(true);

  const [searchTerm, setSearchTerm] = useState('');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('list');
  const navigate = useNavigate();
  const dialog = useDialog();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoadingData(true);
    // Fetch patients
    const { data: patientsData } = await api.getPatients();
    const pList = (patientsData as Patient[]) || [];
    setPatients(pList);

    // Fetch related data to build indicators (Optimization: In a real app, use a View or RPC)
    // We fetch all minimal data to map indicators client-side for this demo
    const [aptsRes, anaRes, docsRes] = await Promise.all([
        api.getAppointments(), // We'll filter client side
        // For Anamneses and Docs, we ideally need a 'getAll' endpoint or we iterate. 
        // Since api.getAnamneses requires ID, we will cheat slightly for this demo 
        // and fetch appointments status. 
        // NOTE: In a real Supabase setup, we'd use a .select('patient_id') on the table directly.
        // Assuming we add a method or just rely on what we can get. 
        // For now, let's assume we can get broad data or we skip deep linking if expensive.
        // To keep it performant without changing API strictly, we will focus on Appointments 
        // and check if we can fetch all docs/anamneses. 
        // Since we can't change supabaseClient easily without user request, 
        // we will implement a lightweight check based on available data or modify api locally if needed.
        // Actually, let's use the existing api logic but we need to fetch ALL for indicators.
        // Since the prompt restricts me to provided files, and api.getAnamneses takes an ID...
        // I will implement a visual trick: I will only show indicators for Appointments (future) 
        // and Mock the others OR extend the logic if I could.
        // Wait, I can use the supabase client directly here since it is exported in supabaseClient.ts? 
        // No, only `api` is usually used.
        // Let's stick to what we can do: Future Appointments are easy (getAppointments returns all).
        // For History/Docs, I will try to fetch them if I can, or I'll skip if it's N+1.
        // Actually, looking at `supabaseClient.ts`, `getAnamneses` filters by ID.
        // I will simply check for Future Appointments for now to be safe, 
        // OR I will assume the `patients` object might eventually have a count.
        // Let's try to query the tables directly using the imported 'api' if I can extend it?
        // The user provided `api` object. 
        // I'll stick to `getAppointments` which returns ALL appointments.
        // For Anamnesis/Docs, I will use a different strategy: I will just show the Appointment indicator 
        // correctly, and maybe skip the others if it's too heavy, OR iterate if list is small (<100).
        // Let's assume list is small < 100 for this "Clinic" demo and do N+1 fetch safely or 
        // better yet, let's use the `api` to fetch all appointments and map them.
        api.getAppointments() 
    ]);

    // Since I cannot change supabaseClient to add `getAllAnamneses`, I will limit indicators 
    // to "Pending Appointments" and "Last Visit" derived from appointments for now to ensure performance,
    // unless I import supabase directly. 
    // Wait, the user provided `import { supabase } ...` in `supabaseClient.ts`.
    // I can import `supabase` in this file if I export it.
    // Checking `supabaseClient.ts`... yes `export const supabase = ...`.
    // So I can do raw queries here for the indicators! Perfect.

    // We need to import supabase from the client file. 
    // Since I can't change the imports easily in the XML without re-writing the whole file,
    // I will use dynamic import or just standard import since I am rewriting the file.

    fetchIndicators(pList);
  };

  // Need to add supabase to imports
  const fetchIndicators = async (currentPatients: Patient[]) => {
     // Lazy load supabase client to avoid circular dep issues if any, or just import at top.
     // I'll add `import { supabase } ...` at top.
     const { supabase } = await import('../supabaseClient');

     const metaMap: Record<string, PatientMeta> = {};
     const today = new Date().toISOString().split('T')[0];

     // Bulk fetch using supabase direct query for performance
     const { data: allApts } = await supabase.from('appointments').select('patient_id, date, status');
     const { data: allAna } = await supabase.from('anamneses').select('patient_id');
     const { data: allDocs } = await supabase.from('documents').select('patient_id');

     currentPatients.forEach(p => {
        const pApts = allApts?.filter((x: any) => x.patient_id === p.id) || [];
        const hasHistory = (allAna?.filter((x: any) => x.patient_id === p.id).length || 0) > 0;
        const hasDocs = (allDocs?.filter((x: any) => x.patient_id === p.id).length || 0) > 0;

        // Future Apt: scheduled and date >= today
        const hasFuture = pApts.some((a: any) => a.status === 'scheduled' && a.date >= today);

        metaMap[p.id] = {
           hasHistory,
           hasDocs,
           hasFutureApt: hasFuture
        };
     });

     setMeta(metaMap);
     setLoadingData(false);
  };

  const handleDelete = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmed = await dialog.confirm(
      "Excluir Paciente", 
      "ATENÇÃO! Isso excluirá o paciente e TODO o seu histórico (Consultas e Anamneses). Deseja continuar?",
      "danger"
    );

    if (!confirmed) return;

    setDeletingId(id);
    const original = [...patients];
    setPatients(prev => prev.filter(p => p.id !== id));

    try {
      const { error } = await api.deletePatient(id);
      if (error) throw error;
    } catch (err: any) {
      console.error(err);
      setPatients(original);
      dialog.alert("Erro", `Erro ao excluir: ${err.message}.`);
    } finally {
      setDeletingId(null);
    }
  };

  const renderIndicators = (patientId: string) => {
     const data = meta[patientId];
     if (!data) return null;

     return (
        <div className="flex gap-1.5 mt-2">
           {data.hasFutureApt && (
              <div className="bg-amber-100 text-amber-700 p-1 rounded-md" title="Consulta Agendada">
                 <Clock size={14} />
              </div>
           )}
           {data.hasHistory && (
              <div className="bg-blue-100 text-blue-700 p-1 rounded-md" title="Possui Histórico/Prontuário">
                 <FileText size={14} />
              </div>
           )}
           {data.hasDocs && (
              <div className="bg-emerald-100 text-emerald-700 p-1 rounded-md" title="Possui Documentos (Receitas/Atestados)">
                 <ScrollText size={14} />
              </div>
           )}
        </div>
     );
  };

  const safePatients = patients || [];

  const filtered = safePatients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.cpf?.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-fade-in-up">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-900">Pacientes</h2>

        <div className="flex w-full md:w-auto gap-2 items-center">
          <div className="bg-white p-1 rounded-lg border border-slate-200 flex items-center mr-2">
             <button 
               onClick={() => setViewMode('grid')}
               className={`p-2 rounded ${viewMode === 'grid' ? 'bg-blue-50 text-blue-900' : 'text-slate-400 hover:text-slate-600'}`}
             >
               <LayoutGrid size={18} />
             </button>
             <button 
               onClick={() => setViewMode('list')}
               className={`p-2 rounded ${viewMode === 'list' ? 'bg-blue-50 text-blue-900' : 'text-slate-400 hover:text-slate-600'}`}
             >
               <List size={18} />
             </button>
          </div>

          <div className="relative flex-1 md:w-64">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
            <input 
              className="w-full pl-10 pr-4 py-2.5 bg-white rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-900 outline-none transition-all shadow-sm"
              placeholder="Buscar por nome ou CPF..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => navigate('/patients/new')}
            className="bg-blue-900 hover:bg-blue-800 text-white px-4 py-2.5 rounded-lg flex items-center gap-2 transition-colors shadow-lg shadow-blue-900/20 font-medium whitespace-nowrap"
          >
            <Plus size={18} /> <span className="hidden md:inline">Novo</span>
          </button>
        </div>
      </div>

      {viewMode === 'grid' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
          {filtered.map(p => (
            <div 
              key={p.id} 
              onClick={() => navigate(`/patients/${p.id}`)}
              className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-all cursor-pointer group hover:border-blue-200 relative"
            >
              <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity z-10">
                <button 
                  onClick={(e) => handleDelete(p.id, e)} 
                  disabled={deletingId === p.id}
                  className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors disabled:opacity-50" 
                  title="Excluir Paciente"
                >
                  {deletingId === p.id ? <Loader size={18} className="animate-spin text-red-600"/> : <Trash2 size={18} />}
                </button>
              </div>

              <div className="flex items-start justify-between mb-2">
                {p.photo_url ? (
                  <img src={p.photo_url} alt={p.name} className="w-14 h-14 rounded-full object-cover border-2 border-slate-100 group-hover:border-blue-500 transition-colors" />
                ) : (
                  <div className="w-14 h-14 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-xl group-hover:bg-blue-900 group-hover:text-white transition-colors">
                    {p.name.charAt(0)}
                  </div>
                )}

                <div className="flex gap-1 pr-8">
                  {p.tags?.slice(0, 2).map(tag => (
                     <span key={tag} className="px-2 py-0.5 bg-blue-50 text-blue-800 rounded text-[10px] uppercase font-bold tracking-wider">{tag}</span>
                  ))}
                </div>
              </div>

              <h3 className="font-bold text-slate-800 text-lg mb-1 truncate group-hover:text-blue-900 transition-colors pr-6">{p.name}</h3>
              <p className="text-sm text-slate-500 font-mono mb-2">{p.cpf || 'CPF não informado'}</p>

              {/* Indicators Grid Mode */}
              {renderIndicators(p.id)}

              <div className="flex items-center justify-between text-xs text-slate-400 border-t border-slate-100 pt-3 mt-3">
                <span className="flex items-center gap-1.5"><Calendar size={14}/> {p.dob ? new Date().getFullYear() - new Date(p.dob).getFullYear() + ' anos' : 'N/A'}</span>
                <span className="flex items-center gap-1.5 text-blue-600 font-medium group-hover:underline">Ver Prontuário <FileText size={14}/></span>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
           <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-200 text-xs uppercase text-slate-500 font-bold">
                 <tr>
                    <th className="px-6 py-4">Paciente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">CPF</th>
                    <th className="px-6 py-4">Contato</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 text-sm">
                 {filtered.map(p => (
                    <tr key={p.id} className="hover:bg-slate-50 transition-colors cursor-pointer group" onClick={() => navigate(`/patients/${p.id}`)}>
                       <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            {p.photo_url ? (
                              <img src={p.photo_url} className="w-8 h-8 rounded-full object-cover" />
                            ) : (
                              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-700 flex items-center justify-center font-bold text-xs">{p.name.charAt(0)}</div>
                            )}
                            <div>
                               <span className="font-bold text-slate-800 group-hover:text-blue-900 block">{p.name}</span>
                               <span className="text-xs text-slate-400">{p.dob ? new Date().getFullYear() - new Date(p.dob).getFullYear() + ' anos' : '-'}</span>
                            </div>
                          </div>
                       </td>
                       <td className="px-6 py-4">
                           {renderIndicators(p.id)}
                       </td>
                       <td className="px-6 py-4 font-mono text-slate-600">{p.cpf || '-'}</td>
                       <td className="px-6 py-4 text-slate-600">{p.contact || '-'}</td>
                       <td className="px-6 py-4 text-right">
                          <button 
                             onClick={(e) => handleDelete(p.id, e)}
                             disabled={deletingId === p.id}
                             className="text-slate-400 hover:text-red-600 p-2 hover:bg-red-50 rounded transition-colors"
                          >
                             {deletingId === p.id ? <Loader size={16} className="animate-spin" /> : <Trash2 size={16} />}
                          </button>
                       </td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>
      )}

      {filtered.length === 0 && (
        <div className="col-span-full py-12 text-center text-slate-400 bg-slate-50 rounded-xl border border-dashed border-slate-200">
          <User size={48} className="mx-auto mb-3 opacity-20" />
          <p>Nenhum paciente encontrado.</p>
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { api } from '../supabaseClient';
import { Appointment } from '../types';
import { DollarSign, TrendingUp, Calendar, CreditCard, PieChart, Printer, CheckCircle, Clock } from 'lucide-react';
import { useAuth } from '../App';
import { useDialog } from '../components/Dialog';

export default function FinancialDashboard() {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  // Date Filter
  const [filter, setFilter] = useState<'today' | 'month' | 'all'>('month');
  // Status Filter: 'all' | 'completed' (Paid) | 'scheduled' (Pending)
  const [paymentStatus, setPaymentStatus] = useState<'all' | 'completed' | 'scheduled'>('all');

  const [loading, setLoading] = useState(true);
  const { user } = useAuth();
  const dialog = useDialog();

  const LOGO_URL = "https://i.ibb.co/n8rLsXSJ/upscalemedia-transformed-1.png";

  useEffect(() => {
    const loadData = async () => {
      const { data } = await api.getAppointments();
      setAppointments((data as Appointment[]) || []);
      setLoading(false);
    };
    loadData();
  }, []);

  const getFilteredData = () => {
    const now = new Date();
    const today = now.toISOString().split('T')[0];
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    return appointments
      .filter(a => a.status !== 'cancelled') // Exclude cancelled from financials by default
      .filter(a => {
        // 1. Filter by Date
        const aDate = new Date(a.date);
        let dateMatch = true;
        if (filter === 'today') dateMatch = a.date === today;
        if (filter === 'month') dateMatch = aDate.getMonth() === currentMonth && aDate.getFullYear() === currentYear;

        // 2. Filter by Status (Payment)
        let statusMatch = true;
        if (paymentStatus === 'completed') statusMatch = a.status === 'completed';
        if (paymentStatus === 'scheduled') statusMatch = a.status === 'scheduled';

        return dateMatch && statusMatch;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  };

  const data = getFilteredData();

  const totalRevenue = data.reduce((sum, a) => sum + (Number(a.price) || 0), 0);
  const totalCount = data.length;

  // Group by Plan
  const revenueByPlan: Record<string, number> = {};
  data.forEach(a => {
    const p = a.plan || 'particular';
    revenueByPlan[p] = (revenueByPlan[p] || 0) + (Number(a.price) || 0);
  });

  const planLabels = Object.keys(revenueByPlan);

  const handlePrintReport = () => {
    const printWindow = window.open('', '_blank', 'width=900,height=600');
    if (!printWindow) {
        dialog.alert("Bloqueio", "Permita popups para imprimir.");
        return;
    }

    const reportDate = new Date().toLocaleDateString('pt-BR');

    // Convert current filters to text
    const periodText = filter === 'today' ? 'Hoje' : filter === 'month' ? 'Mês Atual' : 'Todo o Período';
    const statusText = paymentStatus === 'all' ? 'Todos' : paymentStatus === 'completed' ? 'Realizados (Pagos)' : 'Pendentes (Agendados)';

    const rowsHtml = data.map(item => `
        <tr>
            <td style="padding: 8px; border-bottom: 1px solid #ddd;">${new Date(item.date).toLocaleDateString()}</td>
            <td style="padding: 8px; border-bottom: 1px solid #ddd;">${item.patient?.name || 'N/A'}</td>
            <td style="padding: 8px; border-bottom: 1px solid #ddd;">Dr. ${item.doctor?.name || 'N/A'}</td>
            <td style="padding: 8px; border-bottom: 1px solid #ddd; text-transform: capitalize;">${item.plan || 'Particular'}</td>
            <td style="padding: 8px; border-bottom: 1px solid #ddd;">
                <span style="padding: 2px 6px; border-radius: 4px; font-size: 11px; font-weight: bold; background: ${item.status === 'completed' ? '#dcfce7; color: #166534;' : '#fef3c7; color: #b45309;'}">
                    ${item.status === 'completed' ? 'PAGO' : 'PENDENTE'}
                </span>
            </td>
            <td style="padding: 8px; border-bottom: 1px solid #ddd; text-align: right; font-weight: bold;">R$ ${Number(item.price).toFixed(2)}</td>
        </tr>
    `).join('');

    const html = `
      <!DOCTYPE html>
      <html lang="pt-BR">
      <head>
        <title>Extrato Financeiro - Genesis</title>
        <style>
          body { font-family: sans-serif; padding: 40px; color: #333; }
          .header { display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #333; padding-bottom: 20px; margin-bottom: 30px; }
          h1 { margin: 0; font-size: 24px; text-transform: uppercase; }
          table { width: 100%; border-collapse: collapse; font-size: 12px; }
          th { text-align: left; background: #f3f4f6; padding: 10px; border-bottom: 2px solid #ddd; font-weight: bold; text-transform: uppercase; }
          .totals { margin-top: 30px; text-align: right; font-size: 16px; }
          .badge { font-weight: bold; background: #eee; padding: 4px 8px; border-radius: 4px; }
        </style>
      </head>
      <body>
        <div class="header">
           <div style="display:flex; align-items:center; gap: 15px;">
              <img src="${LOGO_URL}" style="height: 40px;" />
              <div>
                  <h1>Extrato Financeiro</h1>
                  <p style="margin: 5px 0 0 0; font-size: 12px; color: #666;">Genesis Medical System</p>
              </div>
           </div>
           <div style="text-align: right; font-size: 12px;">
              <p>Gerado em: <b>${reportDate}</b></p>
              <p>Período: <b>${periodText}</b></p>
              <p>Status: <b>${statusText}</b></p>
           </div>
        </div>

        <table>
           <thead>
              <tr>
                 <th>Data</th>
                 <th>Paciente</th>
                 <th>Médico</th>
                 <th>Convênio</th>
                 <th>Status</th>
                 <th style="text-align: right;">Valor</th>
              </tr>
           </thead>
           <tbody>
              ${rowsHtml}
           </tbody>
        </table>

        <div class="totals">
           <p>Quantidade de Registros: <b>${totalCount}</b></p>
           <p style="font-size: 20px;">Valor Total: <b style="color: #166534;">R$ ${totalRevenue.toFixed(2)}</b></p>
        </div>

        <script>window.onload = () => window.print();</script>
      </body>
      </html>
    `;

    printWindow.document.write(html);
    printWindow.document.close();
  };

  return (
    <div className="space-y-8 animate-fade-in-up pb-10">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
              <DollarSign className="text-green-600" /> Dashboard Financeiro
           </h2>
           <p className="text-slate-500 text-sm">Visão geral de faturamento e fluxo de caixa</p>
        </div>

        <div className="flex flex-wrap gap-2">
           {/* Date Filters */}
           <div className="flex bg-white rounded-lg p-1 border border-slate-200">
             <button onClick={() => setFilter('today')} className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${filter === 'today' ? 'bg-blue-50 text-blue-900 border border-blue-100' : 'text-slate-500 hover:text-slate-700'}`}>Hoje</button>
             <button onClick={() => setFilter('month')} className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${filter === 'month' ? 'bg-blue-50 text-blue-900 border border-blue-100' : 'text-slate-500 hover:text-slate-700'}`}>Mês</button>
             <button onClick={() => setFilter('all')} className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${filter === 'all' ? 'bg-blue-50 text-blue-900 border border-blue-100' : 'text-slate-500 hover:text-slate-700'}`}>Total</button>
           </div>

           {/* Status Filters */}
           <div className="flex bg-white rounded-lg p-1 border border-slate-200">
             <button onClick={() => setPaymentStatus('all')} className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${paymentStatus === 'all' ? 'bg-slate-100 text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Todos</button>
             <button onClick={() => setPaymentStatus('completed')} className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${paymentStatus === 'completed' ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'text-slate-500 hover:text-slate-700'}`}>Realizados</button>
             <button onClick={() => setPaymentStatus('scheduled')} className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${paymentStatus === 'scheduled' ? 'bg-amber-50 text-amber-700 border border-amber-100' : 'text-slate-500 hover:text-slate-700'}`}>Pendentes</button>
           </div>

           <button 
             onClick={handlePrintReport} 
             className="bg-blue-900 hover:bg-blue-800 text-white px-4 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 shadow-lg shadow-blue-900/20 transition-all"
           >
              <Printer size={14} /> Imprimir Extrato
           </button>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 relative overflow-hidden">
           <div className="absolute top-0 right-0 p-4 opacity-5">
              <DollarSign size={100} />
           </div>
           <div className="flex items-center gap-4 relative z-10">
              <div className="p-3 bg-green-100 text-green-700 rounded-lg">
                 <DollarSign size={28} />
              </div>
              <div>
                 <p className="text-sm text-slate-500 font-medium">Valor Total</p>
                 <p className="text-3xl font-bold text-slate-900">R$ {totalRevenue.toFixed(2)}</p>
              </div>
           </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 relative overflow-hidden">
           <div className="flex items-center gap-4 relative z-10">
              <div className="p-3 bg-blue-100 text-blue-700 rounded-lg">
                 <Calendar size={28} />
              </div>
              <div>
                 <p className="text-sm text-slate-500 font-medium">Qtd. Registros</p>
                 <p className="text-3xl font-bold text-slate-900">{totalCount}</p>
              </div>
           </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 relative overflow-hidden">
           <div className="flex items-center gap-4 relative z-10">
              <div className="p-3 bg-purple-100 text-purple-700 rounded-lg">
                 <TrendingUp size={28} />
              </div>
              <div>
                 <p className="text-sm text-slate-500 font-medium">Ticket Médio</p>
                 <p className="text-3xl font-bold text-slate-900">R$ {totalCount > 0 ? (totalRevenue / totalCount).toFixed(2) : '0.00'}</p>
              </div>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Breakdown Chart */}
        <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
           <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
             <PieChart size={20} className="text-blue-900" /> Por Convênio
           </h3>

           <div className="space-y-5">
             {planLabels.length === 0 && <p className="text-slate-400 text-center py-4">Sem dados para o período.</p>}
             {planLabels.map(plan => {
               const val = revenueByPlan[plan];
               const percent = totalRevenue > 0 ? (val / totalRevenue) * 100 : 0;
               return (
                 <div key={plan}>
                   <div className="flex justify-between text-xs mb-1.5 uppercase font-bold tracking-wide">
                      <span className="text-slate-600">{plan.replace(/_/g, ' ')}</span>
                      <span className="text-slate-900">{percent.toFixed(1)}%</span>
                   </div>
                   <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden mb-1">
                      <div className="bg-blue-600 h-2 rounded-full transition-all duration-500" style={{ width: `${percent}%` }}></div>
                   </div>
                   <p className="text-xs text-right text-slate-400">R$ {val.toFixed(2)}</p>
                 </div>
               )
             })}
           </div>
        </div>

        {/* Detailed Transactions Table */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden">
           <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <CreditCard size={20} className="text-blue-900" /> Detalhamento de Transações
              </h3>
              <span className="text-xs bg-white border border-slate-200 px-2 py-1 rounded text-slate-500">
                 {data.length} registros
              </span>
           </div>

           <div className="overflow-x-auto">
             <table className="w-full text-left text-sm">
               <thead className="bg-slate-50 border-b border-slate-100 text-xs uppercase text-slate-500 font-bold">
                 <tr>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Paciente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Plano</th>
                    <th className="px-6 py-4 text-right">Valor</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100">
                  {data.length === 0 && (
                    <tr>
                       <td colSpan={5} className="px-6 py-10 text-center text-slate-400">Nenhum registro encontrado para os filtros selecionados.</td>
                    </tr>
                  )}
                  {data.map(apt => (
                    <tr key={apt.id} className="hover:bg-slate-50 transition-colors">
                       <td className="px-6 py-4 text-slate-600 whitespace-nowrap">
                          {new Date(apt.date).toLocaleDateString()}
                          <span className="block text-[10px] text-slate-400">{apt.start_time}</span>
                       </td>
                       <td className="px-6 py-4 font-medium text-slate-800">
                          {apt.patient?.name || 'Paciente Removido'}
                          <span className="block text-[10px] text-slate-400 font-normal">Dr. {apt.doctor?.name}</span>
                       </td>
                       <td className="px-6 py-4">
                          {apt.status === 'completed' ? (
                             <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-bold bg-emerald-100 text-emerald-800">
                                <CheckCircle size={12} /> Pago
                             </span>
                          ) : (
                             <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-bold bg-amber-100 text-amber-800">
                                <Clock size={12} /> Pendente
                             </span>
                          )}
                       </td>
                       <td className="px-6 py-4 capitalize text-slate-600">{apt.plan?.replace(/_/g, ' ') || 'Particular'}</td>
                       <td className="px-6 py-4 text-right font-bold text-slate-700">R$ {Number(apt.price).toFixed(2)}</td>
                    </tr>
                  ))}
               </tbody>
             </table>
           </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { api } from '../supabaseClient';
import { Patient } from '../types';
import { Search, Plus, User, FileText, Calendar, Trash2, Loader, LayoutGrid, List, ScrollText, Clock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useDialog } from '../components/Dialog';

interface PatientMeta {
  hasHistory: boolean;
  hasDocs: boolean;
  hasFutureApt: boolean;
}

export default function PatientsPage() {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [meta, setMeta] = useState<Record<string, PatientMeta>>({});
  const [loadingData, setLoadingData] = useState(true);

  const [searchTerm, setSearchTerm] = useState('');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('list');
  const navigate = useNavigate();
  const dialog = useDialog();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoadingData(true);
    // Fetch patients
    const { data: patientsData } = await api.getPatients();
    const pList = (patientsData as Patient[]) || [];
    setPatients(pList);

    // Initialize indicators fetch
    await fetchIndicators(pList);
  };

  // Need to add supabase to imports
  const fetchIndicators = async (currentPatients: Patient[]) => {
     // Lazy load supabase client to avoid circular dep issues if any, or just import at top.
     const { supabase } = await import('../supabaseClient');

     const metaMap: Record<string, PatientMeta> = {};
     const today = new Date().toISOString().split('T')[0];

     // Bulk fetch using supabase direct query for performance
     const { data: allApts } = await supabase.from('appointments').select('patient_id, date, status');
     const { data: allAna } = await supabase.from('anamneses').select('patient_id');
     const { data: allDocs } = await supabase.from('documents').select('patient_id');

     currentPatients.forEach(p => {
        const pApts = allApts?.filter((x: any) => x.patient_id === p.id) || [];
        const hasHistory = (allAna?.filter((x: any) => x.patient_id === p.id).length || 0) > 0;
        const hasDocs = (allDocs?.filter((x: any) => x.patient_id === p.id).length || 0) > 0;

        // Future Apt: scheduled and date >= today
        const hasFuture = pApts.some((a: any) => a.status === 'scheduled' && a.date >= today);

        metaMap[p.id] = {
           hasHistory,
           hasDocs,
           hasFutureApt: hasFuture
        };
     });

     setMeta(metaMap);
     setLoadingData(false);
  };

  const handleDelete = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmed = await dialog.confirm(
      "Excluir Paciente", 
      "ATENÇÃO! Isso excluirá o paciente e TODO o seu histórico (Consultas e Anamneses). Deseja continuar?",
      "danger"
    );

    if (!confirmed) return;

    setDeletingId(id);
    const original = [...patients];
    setPatients(prev => prev.filter(p => p.id !== id));

    try {
      const { error } = await api.deletePatient(id);
      if (error) throw error;
    } catch (err: any) {
      console.error(err);
      setPatients(original);
      dialog.alert("Erro", `Erro ao excluir: ${err.message}.`);
    } finally {
      setDeletingId(null);
    }
  };

  const renderIndicators = (patientId: string) => {
     const data = meta[patientId];
     if (!data) return null;

     return (
        <div className="flex gap-1.5 mt-2">
           {data.hasFutureApt && (
              <div className="bg-amber-100 text-amber-700 p-1 rounded-md" title="Consulta Agendada">
                 <Clock size={14} />
              </div>
           )}
           {data.hasHistory && (
              <div className="bg-blue-100 text-blue-700 p-1 rounded-md" title="Possui Histórico/Prontuário">
                 <FileText size={14} />
              </div>
           )}
           {data.hasDocs && (
              <div className="bg-emerald-100 text-emerald-700 p-1 rounded-md" title="Possui Documentos (Receitas/Atestados)">
                 <ScrollText size={14} />
              </div>
           )}
        </div>
     );
  };

  const safePatients = patients || [];

  const filtered = safePatients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.cpf?.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-fade-in-up">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-900">Pacientes</h2>

        <div className="flex w-full md:w-auto gap-2 items-center">
          <div className="bg-white p-1 rounded-lg border border-slate-200 flex items-center mr-2">
             <button 
               onClick={() => setViewMode('grid')}
               className={`p-2 rounded ${viewMode === 'grid' ? 'bg-blue-50 text-blue-900' : 'text-slate-400 hover:text-slate-600'}`}
             >
               <LayoutGrid size={18} />
             </button>
             <button 
               onClick={() => setViewMode('list')}
               className={`p-2 rounded ${viewMode === 'list' ? 'bg-blue-50 text-blue-900' : 'text-slate-400 hover:text-slate-600'}`}
             >
               <List size={18} />
             </button>
          </div>

          <div className="relative flex-1 md:w-64">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
            <input 
              className="w-full pl-10 pr-4 py-2.5 bg-white rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-900 outline-none transition-all shadow-sm"
              placeholder="Buscar por nome ou CPF..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => navigate('/patients/new')}
            className="bg-blue-900 hover:bg-blue-800 text-white px-4 py-2.5 rounded-lg flex items-center gap-2 transition-colors shadow-lg shadow-blue-900/20 font-medium whitespace-nowrap"
          >
            <Plus size={18} /> <span className="hidden md:inline">Novo</span>
          </button>
        </div>
      </div>

      {viewMode === 'grid' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
          {filtered.map(p => (
            <div 
              key={p.id} 
              onClick={() => navigate(`/patients/${p.id}`)}
              className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-all cursor-pointer group hover:border-blue-200 relative"
            >
              <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity z-10">
                <button 
                  onClick={(e) => handleDelete(p.id, e)} 
                  disabled={deletingId === p.id}
                  className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors disabled:opacity-50" 
                  title="Excluir Paciente"
                >
                  {deletingId === p.id ? <Loader size={18} className="animate-spin text-red-600"/> : <Trash2 size={18} />}
                </button>
              </div>

              <div className="flex items-start justify-between mb-2">
                {p.photo_url ? (
                  <img src={p.photo_url} alt={p.name} className="w-14 h-14 rounded-full object-cover border-2 border-slate-100 group-hover:border-blue-500 transition-colors" />
                ) : (
                  <div className="w-14 h-14 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-xl group-hover:bg-blue-900 group-hover:text-white transition-colors">
                    {p.name.charAt(0)}
                  </div>
                )}

                <div className="flex gap-1 pr-8">
                  {p.tags?.slice(0, 2).map(tag => (
                     <span key={tag} className="px-2 py-0.5 bg-blue-50 text-blue-800 rounded text-[10px] uppercase font-bold tracking-wider">{tag}</span>
                  ))}
                </div>
              </div>

              <h3 className="font-bold text-slate-800 text-lg mb-1 truncate group-hover:text-blue-900 transition-colors pr-6">{p.name}</h3>
              <p className="text-sm text-slate-500 font-mono mb-2">{p.cpf || 'CPF não informado'}</p>

              {/* Indicators Grid Mode */}
              {renderIndicators(p.id)}

              <div className="flex items-center justify-between text-xs text-slate-400 border-t border-slate-100 pt-3 mt-3">
                <span className="flex items-center gap-1.5"><Calendar size={14}/> {p.dob ? new Date().getFullYear() - new Date(p.dob).getFullYear() + ' anos' : 'N/A'}</span>
                <span className="flex items-center gap-1.5 text-blue-600 font-medium group-hover:underline">Ver Prontuário <FileText size={14}/></span>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
           <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-200 text-xs uppercase text-slate-500 font-bold">
                 <tr>
                    <th className="px-6 py-4">Paciente</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">CPF</th>
                    <th className="px-6 py-4">Contato</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 text-sm">
                 {filtered.map(p => (
                    <tr key={p.id} className="hover:bg-slate-50 transition-colors cursor-pointer group" onClick={() => navigate(`/patients/${p.id}`)}>
                       <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            {p.photo_url ? (
                              <img src={p.photo_url} className="w-8 h-8 rounded-full object-cover" />
                            ) : (
                              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-700 flex items-center justify-center font-bold text-xs">{p.name.charAt(0)}</div>
                            )}
                            <div>
                               <span className="font-bold text-slate-800 group-hover:text-blue-900 block">{p.name}</span>
                               <span className="text-xs text-slate-400">{p.dob ? new Date().getFullYear() - new Date(p.dob).getFullYear() + ' anos' : '-'}</span>
                            </div>
                          </div>
                       </td>
                       <td className="px-6 py-4">
                           {renderIndicators(p.id)}
                       </td>
                       <td className="px-6 py-4 font-mono text-slate-600">{p.cpf || '-'}</td>
                       <td className="px-6 py-4 text-slate-600">{p.contact || '-'}</td>
                       <td className="px-6 py-4 text-right">
                          <button 
                             onClick={(e) => handleDelete(p.id, e)}
                             disabled={deletingId === p.id}
                             className="text-slate-400 hover:text-red-600 p-2 hover:bg-red-50 rounded transition-colors"
                          >
                             {deletingId === p.id ? <Loader size={16} className="animate-spin" /> : <Trash2 size={16} />}
                          </button>
                       </td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>
      )}

      {filtered.length === 0 && (
        <div className="col-span-full py-12 text-center text-slate-400 bg-slate-50 rounded-xl border border-dashed border-slate-200">
          <User size={48} className="mx-auto mb-3 opacity-20" />
          <p>Nenhum paciente encontrado.</p>
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { api } from '../supabaseClient';
import { Appointment } from '../types';
import { DollarSign, TrendingUp, Calendar, CreditCard, PieChart, Printer, CheckCircle, Clock, RotateCcw } from 'lucide-react';
import { useAuth } from '../App';
import { useDialog } from '../components/Dialog';

export default function FinancialDashboard() {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  // Date Filter
  const [filter, setFilter] = useState<'today' | 'month' | 'all'>('month');
  // Status Filter: 'all' | 'completed' (Paid) | 'scheduled' (Pending)
  const [paymentStatus, setPaymentStatus] = useState<'all' | 'completed' | 'scheduled'>('all');

  const [loading, setLoading] = useState(true);
  const { user } = useAuth();
  const dialog = useDialog();

  const LOGO_URL = "https://i.ibb.co/n8rLsXSJ/upscalemedia-transformed-1.png";

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const { data } = await api.getAppointments();
    setAppointments((data as Appointment[]) || []);
    setLoading(false);
  };

  const toggleStatus = async (apt: Appointment) => {
    const newStatus = apt.status === 'completed' ? 'scheduled' : 'completed';
    const actionName = newStatus === 'completed' ? 'MARCAR COMO PAGO' : 'MARCAR COMO PENDENTE';

    // Optimistic Update
    setAppointments(prev => prev.map(a => a.id === apt.id ? { ...a, status: newStatus } : a));

    try {
        await api.updateAppointment(apt.id, { status: newStatus });
    } catch (e) {
        // Rollback
        setAppointments(prev => prev.map(a => a.id === apt.id ? { ...a, status: apt.status } : a));
        dialog.alert("Erro", "Não foi possível atualizar o status financeiro.");
    }
  };

  const getFilteredData = () => {
    const now = new Date();
    const today = now.toISOString().split('T')[0];
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    return appointments
      .filter(a => a.status !== 'cancelled') // Exclude cancelled from financials by default
      .filter(a => {
        // 1. Filter by Date
        const aDate = new Date(a.date);
        let dateMatch = true;
        if (filter === 'today') dateMatch = a.date === today;
        if (filter === 'month') dateMatch = aDate.getMonth() === currentMonth && aDate.getFullYear() === currentYear;

        // 2. Filter by Status (Payment)
        let statusMatch = true;
        if (paymentStatus === 'completed') statusMatch = a.status === 'completed';
        if (paymentStatus === 'scheduled') statusMatch = a.status === 'scheduled';

        return dateMatch && statusMatch;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  };

  const data = getFilteredData();

  const totalRevenue = data.reduce((sum, a) => sum + (Number(a.price) || 0), 0);
  const totalCount = data.length;

  // Group by Plan
  const revenueByPlan: Record<string, number> = {};
  data.forEach(a => {
    const p = a.plan || 'particular';
    revenueByPlan[p] = (revenueByPlan[p] || 0) + (Number(a.price) || 0);
  });

  const planLabels = Object.keys(revenueByPlan);

  const handlePrintReport = () => {
    const printWindow = window.open('', '_blank', 'width=900,height=600');
    if (!printWindow) {
        dialog.alert("Bloqueio", "Permita popups para imprimir.");
        return;
    }

